--把职业加入到一个池子里

require "data.JobRandomPool"
JobPoolManager = {}

JobPoolManager.Pools = {}
function JobPoolManager:addJobToPools(item)
    local pool = JobPoolManager.Pools[item.poolId]
    if not pool then
        pool = JobRandomPool.new(item.poolId)
        JobPoolManager.Pools[item.poolId] = pool
    end
    pool:addJobToPool(item)
end

--随机取职业
function JobPoolManager:randomJob(poolId, num)
    local pool = JobPoolManager.Pools[poolId]
    if not pool then
        return {}
    end
    return pool:randomJob(num)
end